if (-not $script:outboundAvailable) {
    Set-ItResult -Skipped -Because "Exchange Online / Get-HostedOutboundSpamFilterPolicy is not available"
    return
}

$policies = Get-HostedOutboundSpamFilterPolicy -ErrorAction Stop
foreach ($policy in @($policies)) {
    if (-not $policy.IsDefault) { continue }
    $policy.AutoForwardingMode | Should -Be 'Off' -Because "ISO A.5.14 / A.8.21 require outbound forwarding rules disabled to prevent stealth data exfiltration via auto-forwarding"
}

if (-not $script:meetingPolicy) {
    Set-ItResult -Skipped -Because "Teams meeting policy endpoint not available in this cloud environment"
    return
}
$script:meetingPolicy['allowAnonymousUsersToStartMeeting'] | Should -Be $false `
    -Because "ISO A.5.14 requires that only authenticated and authorized users can initiate meetings"

if (-not $script:meetingPolicy) {
    Set-ItResult -Skipped -Because "Teams meeting policy endpoint not available in this cloud environment"
    return
}
$script:meetingPolicy['allowExternalNonTrustedMeetingChat'] | Should -Be $false `
    -Because "ISO A.5.14 requires restricting information flow to/from untrusted external participants"

if (-not $script:meetingPolicy) {
    Set-ItResult -Skipped -Because "Teams meeting policy endpoint not available in this cloud environment"
    return
}
$script:meetingPolicy['allowCloudRecording'] | Should -Be $false `
    -Because "ISO A.5.14 requires data minimization - unrestricted cloud recording stores sensitive meeting content"

if (-not $script:spoSettings) {
    Set-ItResult -Skipped -Because "SharePoint settings not available"
    return
}
$script:spoSettings['isResharingByExternalUsersEnabled'] | Should -Be $false `
    -Because "ISO A.5.14 requires controlling information distribution - re-sharing allows uncontrolled propagation of shared content"

if (-not $script:spoSettings) {
    Set-ItResult -Skipped -Because "SharePoint settings not available"
    return
}
$guestExpRequired = $script:spoSettings['externalUserExpirationRequired']
$guestExpDays = $script:spoSettings['externalUserExpireInDays']

$guestExpRequired | Should -Be $true `
    -Because "ISO A.5.14 requires guest access to expire - permanent guest access creates unnecessary long-term risk"

if ($guestExpRequired) {
    $guestExpDays | Should -BeLessOrEqual 30 `
        -Because "ISO A.5.14 requires guest access expiration to be 30 days or less to minimize exposure"
}

if (-not $script:spoSettingsBeta -or $null -eq $script:spoSettingsBeta['isB2BIntegrationEnabled']) {
