} else {
    Set-ItResult -Skipped -Because "AdminAuditLogEnabled property not found on audit config"
}

if (-not $script:graphConnected) {
    Set-ItResult -Skipped -Because "Not authenticated to Microsoft Graph"
    return
}

$enrollProfiles = $null
try {
    $enrollProfiles = Invoke-MgGraphRequest -Method GET -Uri '/beta/deviceManagement/windowsAutopilotDeploymentProfiles' -ErrorAction Stop
} catch {
    if ($_.Exception.Message -match '403|Forbidden|Authorization') {
        Set-ItResult -Skipped -Because "Intune permissions not granted or Intune license not present"
        return
    }
    Set-ItResult -Skipped -Because "Windows Autopilot not configured or not accessible"
    return
}

$profiles = if ($enrollProfiles -and $enrollProfiles['value']) { @($enrollProfiles['value']) } else { @() }
# This is informational - just skip if none exist
if ($profiles.Count -eq 0) {
    Set-ItResult -Skipped -Because "No Windows Autopilot profiles configured - may use alternative enrollment method"
    return
}

$profiles.Count | Should -BeGreaterOrEqual 1 `
    -Because "ISO A.8.19 recommends using automated enrollment to ensure devices are configured with security baselines from first use"

if (-not $script:graphConnected) {
    Set-ItResult -Skipped -Because "Not authenticated to Microsoft Graph"
    return
}

if (-not $script:devicePolicy) {
    Set-ItResult -Skipped -Because "Device registration policy not accessible"
    return
}

$joinType = $script:devicePolicy['azureADJoin']['allowedToJoin']['@odata.type']
$joinRestricted = $joinType -ne '#microsoft.graph.allDeviceRegistrationMembership'

$joinRestricted | Should -Be $true -Because "ISO A.8.2 / A.8.9 require limiting device registration permission to authorized user groups to prevent unmanaged device join"

if (-not $script:exoConnected) {
    Set-ItResult -Skipped -Because "Exchange Online cmdlets not connected"
    return
}

$sharedMailboxes = @(Get-Mailbox -RecipientTypeDetails SharedMailbox -ResultSize 100 -ErrorAction Stop -WarningAction SilentlyContinue)
if ($sharedMailboxes.Count -eq 0) {
    Set-ItResult -Skipped -Because "No shared mailboxes found in this tenant"
    return
}
$enabledAccounts = @()
foreach ($mbx in $sharedMailboxes) {
    try {
        $mgUser = Invoke-MgGraphRequest -Method GET -Uri "/v1.0/users/$($mbx.UserPrincipalName)?`$select=accountEnabled" -ErrorAction SilentlyContinue
